SourceCode.Declaration:
/// <summary>
/// Extension of the <c>InventSum</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(InventSum))]
final class InventSumETGSPAIN_Extension
{

}

Method.Source:
/// <summary>
/// Calculates the total applied quantity for Sales based on the selected dimensions.
/// </summary>
/// <param name="_inventDimParm">
/// Selected dimensions in the Available.
/// </param>
/// <returns>
/// Returns the totalized quantity.
/// </returns>
public Qty ETGSPAINgetSalesApplicationQty(InventDimParm _inventDimParm)
{    
    return abs(this.ETGSPAINcalcApplicationQty(_inventDimParm, true));
}

/// <summary>
/// Calculates the total applied quantity for Purchases based on the selected dimensions.
/// </summary>
/// <param name="_inventDimParm">
/// Selected dimensions in the Available.
/// </param>
/// <returns>
/// Returns the totalized quantity.
/// </returns>
public Qty ETGSPAINgetPurchApplicationQty(InventDimParm _inventDimParm)
{
    return this.ETGSPAINcalcApplicationQty(_inventDimParm, false, true);
}

/// <summary>
/// Calculates the total applied quantity based on the selected dimensions.
/// </summary>
/// <param name="_inventDimParm">
/// Selected dimensions in the Available.
/// </param>
/// <param name="_calcSales">
/// Parameter to determine if we should perform the calculation for Sales.
/// </param>
/// <param name="_calcPurch">
/// Parameter to determine if we should perform the calculation for Purchases.
/// </param>
/// <returns>
/// Returns the totalized quantity.
/// </returns>
public Qty ETGSPAINcalcApplicationQty(InventDimParm _inventDimParm, boolean _calcSales = false, boolean _calcPurch = false)
{
    ETGSPAINInventTransApplication   ETGSPAINInventTransApplication;
    InventDim                   inventDim;  
    PurchTable                  purchTable;
    SalesTable                  salesTable;
    InventDim                   inventDimFilter = this.joinChild();        
    Qty                         qtyPurch        = 0;
    Qty                         qtySales        = 0;

    if (_calcPurch)
    {
        select      sum(PurchApplicationQty)
            from    ETGSPAINInventTransApplication
            index hint DimIdx
            where   ETGSPAINInventTransApplication.ItemId == this.ItemId
        exists join purchTable
            where   purchTable.PurchId     == ETGSPAINInventTransApplication.PurchId
            &&      purchTable.PurchStatus != PurchStatus::Canceled
        #InventDimExistsJoin(ETGSPAINInventTransApplication.inventDimId, inventDim, inventDimFilter, _inventDimParm);      

        qtyPurch = ETGSPAINInventTransApplication.PurchApplicationQty;
    }
    else if (_calcSales)
    {
        select      sum(SalesApplicationQty)
            from    ETGSPAINInventTransApplication
            index hint DimIdx
            where   ETGSPAINInventTransApplication.ItemId == this.ItemId
        exists join salesTable
            where   salesTable.SalesId     == ETGSPAINInventTransApplication.SalesId
            &&      salesTable.SalesStatus != SalesStatus::Canceled
        #InventDimExistsJoin(ETGSPAINInventTransApplication.inventDimId, inventDim, inventDimFilter, _inventDimParm);

        qtySales = ETGSPAINInventTransApplication.SalesApplicationQty;
    }

    return qtyPurch + qtySales;
}
